/** The deployment of an environment */
export type Deployment = {
  /** Commit details of the deployment. */
  readonly commit: Maybe<Commit>;
  /** When the deployment record was created. */
  readonly createdAt: Maybe<Scalars['Time']['output']>;
  /** When the deployment finished. */
  readonly finishedAt: Maybe<Scalars['Time']['output']>;
  /** Global ID of the deployment. */
  readonly id: Maybe<Scalars['ID']['output']>;
  /** Project-level internal ID of the deployment. */
  readonly iid: Maybe<Scalars['String']['output']>;
  /** Pipeline job of the deployment. */
  readonly job: Maybe<CiJob>;
  /** Git-Ref that the deployment ran on. */
  readonly ref: Maybe<Scalars['String']['output']>;
  /** Path to the Git-Ref that the deployment ran on. */
  readonly refPath: Maybe<Scalars['String']['output']>;
  /** Git-SHA that the deployment ran on. */
  readonly sha: Maybe<Scalars['String']['output']>;
  /** Status of the deployment. */
  readonly status: Maybe<DeploymentStatus>;
  /** True or false if the deployment ran on a Git-tag. */
  readonly tag: Maybe<Scalars['Boolean']['output']>;
  /** Git tags that contain this deployment. This field can only be resolved for two deployments in any single request. */
  readonly tags: Maybe<ReadonlyArray<DeploymentTag>>;
  /** User who executed the deployment. */
  readonly triggerer: Maybe<UserCore>;
  /** When the deployment record was updated. */
  readonly updatedAt: Maybe<Scalars['Time']['output']>;
  /** Permissions for the current user on the resource */
  readonly userPermissions: DeploymentPermissions;
  /** Web path to the deployment page. */
  readonly webPath: Maybe<Scalars['String']['output']>;
};

